const formatStatus = global.get('utils.formatStatus', 'initializers') || (t => t);

const topic = msg.topic || '';
const parts = topic.split('/');
// Expected: highland/event/email/deliveries/<source>/received
if (parts.length !== 6 || parts[5] !== 'received') {
    node.warn(`Unexpected topic shape: ${topic}`);
    node.status({ fill: 'red', shape: 'ring', text: formatStatus('Bad topic') });
    return null;
}
const source = parts[4];

// Extract message_id for ACK correlation
const messageId = msg.payload?.message_id;
if (!messageId) {
    node.warn(`Message missing message_id: ${topic}`);
    node.status({ fill: 'red', shape: 'ring', text: formatStatus('No message_id') });
    return null;
}

// Stash the source on the message for downstream visibility
msg.source = source;

// Route
if (source === 'usps') {
    msg.target = 'USPS Parser';
    node.status({ fill: 'green', shape: 'dot', text: formatStatus(`Routed: ${source}`) });
    return [msg, null];
}

// Unrecognized source — emit rejection ACK
node.status({ fill: 'yellow', shape: 'dot', text: formatStatus(`Rejected: ${source}`) });
const ackMsg = {
    topic: 'highland/ack/email',
    payload: {
        message_id: messageId,
        consumer: 'utility_deliveries',
        status: 'rejected',
        processed_at: new Date().toISOString(),
        reason: `Unknown delivery source: ${source}`
    }
};

return [null, ackMsg];

const formatStatus = global.get('utils.formatStatus', 'initializers') || (t => t);

const messageId = msg.payload?.message_id;

const ackMsg = {
    topic: 'highland/ack/email',
    payload: {
        message_id: messageId,
        consumer: 'utility_deliveries',
        status: 'ok',
        processed_at: new Date().toISOString()
    }
};

node.status({ fill: 'grey', shape: 'dot', text: formatStatus('Acked & dropped') });
return [msg, ackMsg];

const formatStatus = global.get('utils.formatStatus', 'initializers') || (t => t);

const subject = msg.payload?.subject || '';

if (subject.startsWith('Your Daily Digest for ')) {
    msg.target = 'Parse USPS Digest';
    msg.subject_type = 'digest';
    node.status({ fill: 'green', shape: 'dot', text: formatStatus('Digest') });
    return [msg, null];
}

if (subject.startsWith('Your Mail Was Delivered ')) {
    msg.target = 'Parse USPS Delivered';
    msg.subject_type = 'mail_delivered';
    node.status({ fill: 'green', shape: 'dot', text: formatStatus('Mail Delivered') });
    return [msg, null];
}

// Unrecognized subject — ACK ok and drop. M2 will route OFD and Item Delivered here.
const truncated = subject.length > 30 ? subject.slice(0, 27) + '...' : subject;
node.status({ fill: 'yellow', shape: 'dot', text: formatStatus(`Unmatched: ${truncated}`) });

return [null, msg];

const formatStatus = global.get('utils.formatStatus', 'initializers') || (t => t);

const messageId = msg.payload?.message_id;
const deliveredAt = msg.payload?.received_at;  // canonical timestamp per § Confirmed parse signals

if (!deliveredAt) {
    node.status({ fill: 'red', shape: 'ring', text: formatStatus('No received_at') });
    node.warn(`Mail Delivered missing received_at for ${messageId}`);
    const ackMsg = {
        topic: 'highland/ack/email',
        payload: {
            message_id: messageId,
            consumer: 'utility_deliveries',
            status: 'parse_error',
            processed_at: new Date().toISOString(),
            reason: 'Mail Delivered missing received_at'
        }
    };
    return [msg, ackMsg];
}

msg.payload = {
    type: 'mail_delivered',
    delivered_at: deliveredAt
};
msg.topic = 'sm/letter_mail';

const ackMsg = {
    topic: 'highland/ack/email',
    payload: {
        message_id: messageId,
        consumer: 'utility_deliveries',
        status: 'ok',
        processed_at: new Date().toISOString()
    }
};

node.status({ fill: 'green', shape: 'dot', text: formatStatus('Mail delivered') });
return [msg, ackMsg];

const formatStatus = global.get('utils.formatStatus', 'initializers') || (t => t);

// Capture identifiers BEFORE we replace msg.payload with the typed signal
const messageId = msg.payload?.message_id;
const digestReceivedAt = msg.payload?.received_at;  // already Z-form UTC from Email Ingress
const html = msg.payload?.body_html || '';

const match = html.match(/You have (\d+) mailpiece\(s\) and (\d+) inbound package\(s\)/);

if (!match) {
    node.status({ fill: 'red', shape: 'ring', text: formatStatus('Count line not found') });
    node.warn(`Digest count line not found in HTML body for ${messageId}`);
    const ackMsg = {
        topic: 'highland/ack/email',
        payload: {
            message_id: messageId,
            consumer: 'utility_deliveries',
            status: 'parse_error',
            processed_at: new Date().toISOString(),
            reason: 'Digest count line not found in HTML body'
        }
    };
    // No signal to the SM on parse_error — return msg untouched for link-call control flow only
    return [msg, ackMsg];
}

const pieceCount = parseInt(match[1], 10);
// match[2] = package count from digest; intentionally discarded per design

// Replace payload with the typed SM signal; _linkSource is preserved on msg
msg.payload = {
    type: 'digest_parsed',
    piece_count: pieceCount,
    digest_received_at: digestReceivedAt
};
msg.topic = 'sm/letter_mail';

const ackMsg = {
    topic: 'highland/ack/email',
    payload: {
        message_id: messageId,
        consumer: 'utility_deliveries',
        status: 'ok',
        processed_at: new Date().toISOString()
    }
};

node.status({
    fill: 'green',
    shape: 'dot',
    text: formatStatus(`Digest: ${pieceCount} piece${pieceCount === 1 ? '' : 's'}`)
});
return [msg, ackMsg];

const formatStatus = global.get('utils.formatStatus', 'initializers') || (t => t);

const sig = msg.payload || {};
const type = sig.type;
const now = new Date().toISOString();

// Read current state from flow context (default store, persists across deploys)
let state = flow.get('usps_mail_state') || {
    state: 'NOT_EXPECTING',
    expected_pieces: null,
    digest_received_at: null,
    delivered_at: null,
    timestamp: now
};

let stateChanged = false;
let eventTopic = null;
let eventPayload = null;

switch (type) {
    case 'digest_parsed': {
        if (sig.piece_count > 0) {
            state = {
                ...state,
                state: 'EXPECTING',
                expected_pieces: sig.piece_count,
                digest_received_at: sig.digest_received_at,
                timestamp: now
            };
            stateChanged = true;
            eventTopic = 'highland/event/deliveries/letter_mail/expected';
            eventPayload = {
                piece_count: sig.piece_count,
                timestamp: now
            };
            node.status({
                fill: 'green',
                shape: 'dot',
                text: formatStatus(`EXPECTING (${sig.piece_count})`)
            });
        } else {
            // piece_count === 0 → package-only digest; no state transition
            node.status({
                fill: 'grey',
                shape: 'dot',
                text: formatStatus('Digest 0 pieces — no-op')
            });
        }
        break;
    }

    case 'mail_delivered': {
        state = {
            ...state,
            state: 'DELIVERED',
            delivered_at: sig.delivered_at,
            timestamp: now
        };
        stateChanged = true;
        eventTopic = 'highland/event/deliveries/letter_mail/delivered';
        eventPayload = { timestamp: now };
        msg.notification_hint = 'mail_delivered';
        node.status({
            fill: 'green',
            shape: 'dot',
            text: formatStatus(`DELIVERED (from ${flow.get('usps_mail_state')?.state || 'NOT_EXPECTING'})`)
        });
        break;
    }

    case 'exception_check': {
        if (state.state === 'EXPECTING') {
            state = {
                ...state,
                state: 'EXCEPTION',
                timestamp: now
            };
            stateChanged = true;
            eventTopic = 'highland/event/deliveries/letter_mail/exception';
            eventPayload = {
                expected_pieces: state.expected_pieces,
                digest_received_at: state.digest_received_at,
                timestamp: now
            };
            msg.notification_hint = 'mail_exception';
            node.status({
                fill: 'yellow',
                shape: 'dot',
                text: formatStatus('EXCEPTION')
            });
        } else {
            node.status({
                fill: 'grey',
                shape: 'dot',
                text: formatStatus(`Exception check: ${state.state} — no-op`)
            });
        }
        break;
    }

    case 'midnight_rollover': {
        state = {
            state: 'NOT_EXPECTING',
            expected_pieces: null,
            digest_received_at: null,
            delivered_at: null,
            timestamp: now
        };
        stateChanged = true;
        // No event for rollover per design — only the state republish
        node.status({
            fill: 'blue',
            shape: 'dot',
            text: formatStatus('NOT_EXPECTING (rollover)')
        });
        break;
    }

    default: {
        node.warn(`Unknown signal type: ${type}`);
        break;
    }
}

if (stateChanged) {
    flow.set('usps_mail_state', state);

    const stateMsg = {
        topic: 'highland/state/deliveries/letter_mail',
        payload: { ...state, source: 'informed_delivery' },
        retain: true,
        qos: 1
    };
    node.send([null, stateMsg]);

    if (eventTopic) {
        const eventMsg = {
            topic: eventTopic,
            payload: eventPayload,
            retain: false,
            qos: 1
        };
        node.send([null, eventMsg]);
    }
}

// Always return msg on output 1 so the link-call chain unwinds cleanly,
// regardless of whether a transition occurred.
return [msg, null];

switch (msg.topic) {
    case 'exception-check':
        msg.payload = { type: 'exception_check' };
        msg.topic = 'sm/letter_mail';
        break;
    case 'midnight-rollover':
        msg.payload = { type: 'midnight_rollover' };
        msg.topic = 'sm/letter_mail';
        break;
    default:
        node.warn(`Unknown schedule: ${msg.topic}`);
        return null;
}

return msg;

const formatStatus = global.get('utils.formatStatus', 'initializers') || (t => t);

const hint = msg.notification_hint;
if (!hint) {
    node.status({});
    return msg;  // no notification produced for this transition
}

// Strip the hint immediately — it's a transient signal, doesn't leave the group
delete msg.notification_hint;

// Reach into flow context for the freshly-persisted state, since msg.payload is
// still the inbound parser-signal at this point in the synchronous return path
const state = flow.get('usps_mail_state') || {};
const now = state.timestamp || new Date().toISOString();

let notification;
switch (hint) {
    case 'mail_delivered': {
        const piece = state.expected_pieces;
        const message = (piece && piece > 0)
            ? `Your mail (${piece} piece${piece === 1 ? '' : 's'}) has been delivered.`
            : 'Mail has been delivered.';
        notification = {
            notification_id: 'usps.mail_delivered',
            timestamp: now,
            source: 'deliveries.usps',
            correlation_id: 'usps_mail',
            title: 'Mail delivered',
            largeIcon: 'mdi:email',
            smallIcon: 'mdi:check-circle',
            smallIconColor: '#00CC00',
            message
        };
        break;
    }
    case 'mail_exception': {
        const expected = state.expected_pieces;
        const pieceText = expected
            ? `${expected} piece${expected === 1 ? '' : 's'} expected`
            : 'mail expected';
        notification = {
            notification_id: 'usps.mail_exception',
            timestamp: now,
            source: 'deliveries.usps',
            correlation_id: 'usps_mail',
            title: 'Mail running late',
            largeIcon: 'mdi:email',
            smallIcon: 'mdi:alert-circle',
            smallIconColor: '#CC0000',
            message: `${pieceText} from today's digest hasn't been delivered yet.`
        };
        break;
    }
    default: {
        node.warn(`Unknown notification_hint: ${hint}`);
        node.status({ fill: 'red', shape: 'ring', text: formatStatus(`Bad hint: ${hint}`) });
        return msg;
    }
}

msg.notification = notification;
node.status({ fill: 'blue', shape: 'dot', text: formatStatus(`Built: ${hint}`) });
return msg;

const formatStatus = global.get('utils.formatStatus', 'initializers') || (t => t);

const notification = msg.notification;
if (!notification) {
    node.status({});
    return [msg, null];
}

// Strip the envelope before continuing the return path
delete msg.notification;

const notifyMsg = {
    topic: 'highland/event/notify',
    payload: notification,
    retain: false,
    qos: 1
};

node.status({
    fill: 'blue',
    shape: 'dot',
    text: formatStatus(`Notify: ${notification.notification_id}`)
});

return [msg, notifyMsg];
